{
  "type": "infographic poster",
  "style": "cute flat vector illustration, cozy, warm, soft shading, {argument name=\"color palette\" default=\"pastel Morandi colors, soft pinks, purples, and warm tones\"}",
  "character": "{argument name=\"character description\" default=\"young woman with shoulder-length brown hair wearing a pinkish-purple shirt\"}",
  "layout": {
    "structure": "4 rows, 3 columns. Top row is a merged header. Rows 2-4 contain 9 individual panels.",
    "header": {
      "title": "{argument name=\"main title\" default=\"情绪不好了？\"}",
      "subtitle": "{argument name=\"subtitle\" default=\"8个让你瞬间变好的方法\"}",
      "sub_subtitle": "写给焦虑的你，快来看看",
      "visual": "character hugging herself, surrounded by yellow sparkles and hearts"
    },
    "grid_panels": [
      {
        "id": 1,
        "title": "1. 深呼吸",
        "text": "调节神经，缓解紧张情绪。",
        "visual": "character with eyes closed, smiling, surrounded by clouds"
      },
      {
        "id": 2,
        "title": "2. 去户外散步",
        "text": "接触自然，让心静下来。",
        "visual": "character walking outdoors among green trees and bushes"
      },
      {
        "id": 3,
        "title": "3. 写情绪日记",
        "text": "把烦恼写下，大脑会更轻松。",
        "visual": "character sitting at a desk writing in a notebook with a pen, floating hearts"
      },
      {
        "id": 4,
        "title": "4. 抱抱自己",
        "text": "给予自己温暖和安慰。",
        "visual": "character hugging herself with eyes closed, floating hearts"
      },
      {
        "id": 5,
        "title": "5. 听听音乐",
        "text": "让舒缓的旋律治愈心灵。",
        "visual": "character wearing large white headphones, eyes closed, floating colorful music notes"
      },
      {
        "id": 6,
        "title": "6. 找人倾诉",
        "text": "分享你的烦恼，让压力释放。",
        "visual": "character holding a smartphone, talking to another similar-looking girl, floating hearts"
      },
      {
        "id": 7,
        "title": "7. 看看天空",
        "text": "感受天空的辽阔，让心情变好。",
        "visual": "character looking up at a blue sky with white clouds and sparkles"
      },
      {
        "id": 8,
        "title": "8. 冥想",
        "text": "专注于呼吸，找回内心的宁静。",
        "visual": "an open notebook, a pen, and a pink flower on a desk"
      },
      {
        "id": 9,
        "title": "none",
        "text": "{argument name=\"footer text\" default=\"转发收藏，每天都要关爱自己！\"}",
        "visual": "character sitting cross-legged in a meditation pose, eyes closed, with a glowing halo behind her head"
      }
    ]
  }
}

{
  "type": "教育信息图",
  "style": "简洁、现代的教科书插图风格，采用浅蓝与白色配色方案",
  "header": "{argument name=\"main title\" default=\"高中地理：大气环流的示例说明\"}",
  "layout": {
    "top_left_column": {
      "section_1": {
        "title": "{argument name=\"section one title\" default=\"一、什么是大气环流？\"}",
        "content": "1 段关于全球空气运动的简短解释"
      },
      "section_2": {
        "title": "二、成因",
        "content": "3 个要点，解释太阳辐射、垂直运动和地转偏向力"
      }
    },
    "top_right_column": {
      "section_3": {
        "title": "{argument name=\"diagram title\" default=\"三、三圈环流示意图\"}",
        "diagram_features": [
          "显示南北纬 0 度至 90 度的地球横截面",
          "颜色编码的气压带：红色（赤道）、黄色（副热带）、绿色（副极地）、蓝色（极地）",
          "指示气流方向的箭头"
        ],
        "circulation_cells": {
          "count": 3,
          "labels": [
            "极地环流 (高纬环流)",
            "中纬环流 (费雷尔环流)",
            "低纬环流 (哈德莱环流)"
          ],
          "descriptions": "3 个文本框，详细说明每个环流圈的特征"
        },
        "legend": {
          "title": "图例",
          "items": "3 种箭头类型：红色（上升）、蓝色（下沉）、绿色（水平）"
        }
      }
    },
    "bottom_row": {
      "section_4": {
        "title": "{argument name=\"examples title\" default=\"四、生活中的实例\"}",
        "examples": {
          "count": 3,
          "items": [
            {
              "subtitle": "1 赤道多雨，副热带沙漠广布",
              "images": "2 张照片：热带雨林和沙漠",
              "text": "2 个解释气候的文本块"
            },
            {
              "subtitle": "2 中纬度盛行西风",
              "images": "1 张照片：海岸边被风吹弯的树木",
              "text": "1 个解释西风带的文本块"
            },
            {
              "subtitle": "3 极地东风",
              "images": "1 张照片：雪山",
              "text": "1 个解释极地东风带的文本块"
            }
          ]
        }
      }
    },
    "footer": {
      "label": "{argument name=\"footer label\" default=\"小结：\"}",
      "icon": "lightbulb",
      "content": "1 句关于全球气候机制的总结"
    }
  }
}

